Resource: module.kms.aws_kms_key.secrets
File: /modules/kms/main.tf:91-138
<pre>
91: resource "aws_kms_key" "secrets" {
92:   description             = "${local.name_prefix} secrets encryption (Secrets Manager)"
93:   deletion_window_in_days = var.deletion_window_in_days
94:   enable_key_rotation     = var.enable_key_rotation
95:   multi_region            = false
96: 
97:   policy = jsonencode({
98:     Version = "2012-10-17"
99:     Statement = [
100:       {
101:         Sid    = "RootAccountFullAccess"
102:         Effect = "Allow"
103:         Principal = {
104:           AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
105:         }
106:         Action   = "kms:*"
107:         Resource = "*"
108:       },
109:       {
110:         Sid    = "AllowSecretsManagerService"
111:         Effect = "Allow"
112:         Principal = {
113:           AWS = "*"
114:         }
115:         Action = [
116:           "kms:Encrypt",
117:           "kms:Decrypt",
118:           "kms:ReEncrypt*",
119:           "kms:GenerateDataKey*",
120:           "kms:DescribeKey"
121:         ]
122:         Resource = "*"
123:         Condition = {
124:           StringEquals = {
125:             "kms:ViaService"    = "secretsmanager.${data.aws_region.current.name}.amazonaws.com"
126:             "kms:CallerAccount" = data.aws_caller_identity.current.account_id
127:           }
128:         }
129:       }
130:     ]
131:   })
132: 
133:   tags = {
134:     Name       = "${local.name_prefix}-secrets-key"
135:     Tier       = "secrets"
136:     Compliance = "FedRAMP-Moderate"
137:   }
138: }
</pre>

